namespace ValiCraft;

/// <summary>
/// Defines a module that provides ValiCraft validator registration metadata.
/// Implementations are generated by the ValiCraft source generator for each project containing validators.
/// </summary>
public interface IValiCraftModule
{
    /// <summary>
    /// Gets the validator registrations defined in this module.
    /// Each tuple contains the service interface type (e.g. <c>typeof(IValidator&lt;T&gt;)</c>)
    /// and the concrete implementation type.
    /// </summary>
    /// <returns>An enumerable of (service type, implementation type) tuples.</returns>
    static abstract IEnumerable<(Type ServiceType, Type ImplementationType)> GetValidatorRegistrations();
}
